# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

# Database connection details
rds_host = "your_rds_host"
username = "your_username"
password = "your_password"
database = "your_database"

def lambda_handler(event, context):
    connection = pymysql.connect(host=rds_host, user=username, password=password, database=database)
    
    search_params = event.get('queryStringParameters', {})
    query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    values = []

    if 'name' in search_params:
        conditions.append("name LIKE %s")
        values.append(f"%{search_params['name']}%")
    
    if 'category' in search_params:
        conditions.append("category = %s")
        values.append(search_params['category'])
    
    if 'price_min' in search_params:
        conditions.append("price >= %s")
        values.append(search_params['price_min'])
    
    if 'price_max' in search_params:
        conditions.append("price <= %s")
        values.append(search_params['price_max'])

    if conditions:
        query += " AND " + " AND ".join(conditions)

    try:
        with connection.cursor() as cursor:
            cursor.execute(query, values)
            results = cursor.fetchall()
            products = []
            for row in results:
                products.append({
                    'id': row[0],
                    'name': row[1],
                    'category': row[2],
                    'price': row[3],
                })
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    
    finally:
        connection.close()